for i = 1:size(ConData,1)
    if strcmp(ConData(i,end),'')
        ConData{i,end} = NaN;
    end
end

% Also get timestamp for Log file.
D = dir(filename);
DateTag = D.date;
DateTag(strfind(DateTag,' '))='_';
DateTag(strfind(DateTag,':'))='-';
% Get timestamps and sort data from text file and use it to calculate metrics like time gap
% between actuator queries.
% Three actuators with these COM numbers (note, different labeling than
% Windows COMs). Find the three COM numbers.
COMnums = sort(unique([ConData{~isnan([ConData{:,end}]),end}]));

% Do calculations for each COM
for i = 1:length(COMnums)
    close all;
    h = figure('position',[100 100 1000 400]);
    % Find the rows corresponding to the three COM ports. 
    COMs = ConData(:,end);
    ind = [];
    ind = find([ConData{:,end}]==COMnums(i));
    % For each COM, take that row and the row above it.
    ind = sort([ind (ind-1)]);

    dat = ConData(ind,:);
    
    % Omit 'R: rows, which stand for 'response' (I think)
    Rs = find(strcmp(dat(:,2),'R:')); Rs = sort([Rs; (Rs+1)]);
    dat(Rs,:) = [];
    
    % Plot time gaps between consecutive Queries ('Q:' rows (I think))
    t = datenum(dat(2:2:end,4));
    
    t = (t-t(1))*86400;
    
    d = diff(t*1000);
    
    ran = 1:(length(t)-1)'; %50;
    
    subplot(1,2,1)
    plot(t(ran),'.-');
    xlabel('Array element'); ylabel('time (s)');
    subplot(1,2,2)
    plot(d(ran));
    xlabel('Array element'); ylabel('lag between Q''s (ms)');
    0;
    
    saveas(gcf,[UpOneDir(filename) 'TimeLags_' DateTag 'COM' num2str(COMnums(i)) '.fig'])
end

